   157→                // Make sure to clone so as to not mutate the original
   158→                List<APyObj> comboClone = new ArrayList<>(combo);
   159→                comboClone.add(0, arg);
   160→                allCombos.add(comboClone);
   161→            }
   162→        }
   163→        return allCombos;
