     6→import java.util.ArrayList;
     7→import java.util.HashSet;
     8→import java.util.List;
     9→import java.util.Set;
    10→
    11→/**
    12→ * Stateless class that is a wrapper for a greedy approximation of the set cover
    13→ * algorithm. Running the hitting set algorithm on the results of testing yields a
    14→ * "concise" (approximately minimal) set of test cases that still catches every known
    15→ * (based on the base test set) incorrect implementation.
    16→ */
    17→public class ConciseSetGenerator {
    18→
    19→    /**
    20→     * A greedy approximation of the set cover algorithm. Given a set of incorrect
    21→     * implementations (S), a set of test cases (B), and list "mapping" each test case
    22→     * (index i) to the set of implementations (Si) that it caught -- all contained within
    23→     * results --, finds an approximately minimal subset of B (M) such that all of the
    24→     * incorrect implementations are caught by at least one element in M.
    25→     *
    26→     * @param results the results of running all tests in B on all files in S
    27→     * @return M, a set of test cases that is an approximately minimal set covering
    28→     */
    29→    public static Set<TestCase> setCover(TestResults results) {
    30→
    31→        // Initialize the structure to return
    32→        HashSet<TestCase> hittingSet = new HashSet<>();
    33→
    34→        // We'll be mutating both caseToFiles and wrongSet, so make copies
    35→        List<Set<Integer>> caseToFiles = new ArrayList<>();
    36→        for (Set<Integer> set : results.getCaseToFiles()) {
    37→            caseToFiles.add(new HashSet<>(set));
    38→        }
    39→        Set<Integer> wrongSet = new HashSet<>(results.getWrongSet());
    40→
    41→        // Select tests until we've "covered" every program that was initially in the
    42→        // wrong set
    43→        while (wrongSet.size() > 0) {
    44→            int maxFilesCaught = 0;
    45→            int caseOfMaxFiles = -1;
    46→
    47→            // Find the test case that covers the most heretofore-uncovered files
    48→            for (int caseIndex = 0; caseIndex < caseToFiles.size(); caseIndex++) {
    49→                Set<Integer> filesCaught = caseToFiles.get(caseIndex);
    50→                if (filesCaught.size() > maxFilesCaught) {
    51→                    maxFilesCaught = filesCaught.size();
    52→                    caseOfMaxFiles = caseIndex;
    53→                }
    54→            }
    55→
    56→            // Remove all covered files from the wrongSet
    57→            HashSet<Integer> coveredFiles =
    58→                new HashSet<>(caseToFiles.get(caseOfMaxFiles));
    59→            wrongSet.removeAll(coveredFiles);
    60→
    61→            // Update the caseToFiles mapping such that the set of files caught by each
    62→            // test no longer includes the newly-covered files
    63→            for (Set<Integer> filesCaught : caseToFiles) {
    64→                filesCaught.removeAll(coveredFiles);
    65→            }
    66→
    67→            // Add the selected test case to the hitting set
    68→            hittingSet.add(results.getTestCase(caseOfMaxFiles));
    69→        }
    70→
    71→        // Return the hitting set
    72→        return hittingSet;
    73→    }
    74→}

