package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

/**
 * A simple data class representing a parsed configuration file.
 */
public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    /**
     * Constructs a ConfigFile with the given fields.
     *
     * @param funcName the name of the function being tested
     * @param nodes    the list of PyNodes for function arguments
     * @param numRand  the number of random test cases to generate
     */
    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Returns the function name.
     */
    public String getFuncName() {
        return this.funcName;
    }

    /**
     * Returns the number of random test cases.
     */
    public int getNumRand() {
        return this.numRand;
    }

    /**
     * Returns the list of PyNodes for the function arguments.
     */
    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }
}

package main.rice.parse;

import main.rice.node.*;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.util.ArrayList;
import java.util.List;

/**
 * Parses a JSON configuration file into a ConfigFile object.
 *
 * JSON format:
 * {
 *   "fname": "functionName",
 *   "types": ["int", "list(bool)", ...],
 *   "exhaustive domain": ["1~3", "0~2(0~1", ...],
 *   "random domain": ["1~10", "0~5(0~1", ...],
 *   "num random": 10
 * }
 *
 * Domain format for primitives:   "lower~upper"  or  "[v1,v2,...]"
 * Domain format for str:          "sizeLow~sizeHigh(charDomain"
 * Domain format for list/set/tuple: "sizeLow~sizeHigh(innerDomain"
 * Domain format for dict:         "sizeLow~sizeHigh(keyDomain(valueDomain"
 *   where ( is used as separator at each nesting level.
 */
public class ConfigFileParser {

    /**
     * Parses the given JSON string into a ConfigFile.
     *
     * @param contents the JSON string to parse
     * @return a ConfigFile object
     * @throws InvalidConfigException if the JSON is malformed or invalid
     */
    public ConfigFile parse(String contents) throws InvalidConfigException {
        // Parse JSON
        JSONObject json;
        try {
            json = new JSONObject(contents);
        } catch (JSONException e) {
            throw new InvalidConfigException("Not valid JSON: " + e.getMessage());
        }

        // Extract required fields
        String fname = extractString(json, "fname");
        JSONArray typesArr = extractArray(json, "types");
        JSONArray exDomsArr = extractArray(json, "exhaustive domain");
        JSONArray ranDomsArr = extractArray(json, "random domain");
        int numRand = extractNonNegInt(json, "num random");

        // Validate array lengths match
        int n = typesArr.length();
        if (exDomsArr.length() != n || ranDomsArr.length() != n) {
            throw new InvalidConfigException(
                "types, exhaustive domain, and random domain must have the same length");
        }

        // Parse each type + domain triple into a node
        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            Object typeObj = typesArr.get(i);
            Object exObj = exDomsArr.get(i);
            Object ranObj = ranDomsArr.get(i);

            if (!(typeObj instanceof String)) {
                throw new InvalidConfigException(
                    "types must contain strings, found: " + typeObj);
            }
            if (!(exObj instanceof String)) {
                throw new InvalidConfigException(
                    "exhaustive domain must contain strings, found: " + exObj);
            }
            if (!(ranObj instanceof String)) {
                throw new InvalidConfigException(
                    "random domain must contain strings, found: " + ranObj);
            }

            String typeStr = (String) typeObj;
            String exStr = (String) exObj;
            String ranStr = (String) ranObj;

            // Reject spaces in type or domain strings
            if (typeStr.contains(" ")) {
                throw new InvalidConfigException("Spurious space in type: " + typeStr);
            }
            if (exStr.contains(" ")) {
                throw new InvalidConfigException(
                    "Spurious space in exhaustive domain: " + exStr);
            }
            if (ranStr.contains(" ")) {
                throw new InvalidConfigException(
                    "Spurious space in random domain: " + ranStr);
            }

            nodes.add(buildNode(typeStr, exStr, ranStr));
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    // ==================== Field Extractors ====================

    private String extractString(JSONObject json, String key)
            throws InvalidConfigException {
        if (!json.has(key)) {
            throw new InvalidConfigException("Missing required field: " + key);
        }
        Object val;
        try {
            val = json.get(key);
        } catch (JSONException e) {
            throw new InvalidConfigException("Error reading field: " + key);
        }
        if (!(val instanceof String)) {
            throw new InvalidConfigException(
                "Field '" + key + "' must be a string, got: " + val);
        }
        return (String) val;
    }

    private JSONArray extractArray(JSONObject json, String key)
            throws InvalidConfigException {
        if (!json.has(key)) {
            throw new InvalidConfigException("Missing required field: " + key);
        }
        Object val;
        try {
            val = json.get(key);
        } catch (JSONException e) {
            throw new InvalidConfigException("Error reading field: " + key);
        }
        if (!(val instanceof JSONArray)) {
            throw new InvalidConfigException(
                "Field '" + key + "' must be an array, got: " + val);
        }
        return (JSONArray) val;
    }

    private int extractNonNegInt(JSONObject json, String key)
            throws InvalidConfigException {
        if (!json.has(key)) {
            throw new InvalidConfigException("Missing required field: " + key);
        }
        Object val;
        try {
            val = json.get(key);
        } catch (JSONException e) {
            throw new InvalidConfigException("Error reading field: " + key);
        }
        if (!(val instanceof Integer) && !(val instanceof Long)) {
            throw new InvalidConfigException(
                "Field '" + key + "' must be an integer, got: " + val);
        }
        int v = ((Number) val).intValue();
        if (v < 0) {
            throw new InvalidConfigException(
                "Field '" + key + "' must be non-negative, got: " + v);
        }
        return v;
    }

    // ==================== Top-Level Node Builder ====================

    /**
     * Builds a fully-configured APyNode for the given type and domain strings.
     * Validates that the entire domain strings are consumed.
     */
    private APyNode<?> buildNode(String typeStr, String exStr, String ranStr)
            throws InvalidConfigException {
        int[] exPos = {0};
        int[] ranPos = {0};
        APyNode<?> node = buildNodeHelper(typeStr, exStr, exPos, ranStr, ranPos);
        if (exPos[0] != exStr.length()) {
            throw new InvalidConfigException(
                "Spurious characters in exhaustive domain: "
                    + exStr.substring(exPos[0]));
        }
        if (ranPos[0] != ranStr.length()) {
            throw new InvalidConfigException(
                "Spurious characters in random domain: "
                    + ranStr.substring(ranPos[0]));
        }
        return node;
    }

    /**
     * Recursive helper: builds a node for the given type string,
     * consuming from exStr[exPos[0]] and ranStr[ranPos[0]].
     */
    @SuppressWarnings({"unchecked", "rawtypes"})
    private APyNode<?> buildNodeHelper(String typeStr,
                                        String exStr, int[] exPos,
                                        String ranStr, int[] ranPos)
            throws InvalidConfigException {

        switch (typeStr) {
            case "int": {
                String exSeg = consumeSegment(exStr, exPos);
                String ranSeg = consumeSegment(ranStr, ranPos);
                List<Integer> exDom = parseIntDomain(exSeg);
                List<Integer> ranDom = parseIntDomain(ranSeg);
                PyIntNode node = new PyIntNode();
                node.setExDomain(exDom);
                node.setRanDomain(ranDom);
                return node;
            }
            case "bool": {
                String exSeg = consumeSegment(exStr, exPos);
                String ranSeg = consumeSegment(ranStr, ranPos);
                List<Integer> exDom = parseIntDomain(exSeg);
                List<Integer> ranDom = parseIntDomain(ranSeg);
                PyBoolNode node = new PyBoolNode();
                node.setExDomain(exDom);
                node.setRanDomain(ranDom);
                return node;
            }
            case "float": {
                String exSeg = consumeSegment(exStr, exPos);
                String ranSeg = consumeSegment(ranStr, ranPos);
                List<Double> exDom = parseFloatDomain(exSeg);
                List<Double> ranDom = parseFloatDomain(ranSeg);
                PyFloatNode node = new PyFloatNode();
                node.setExDomain(exDom);
                node.setRanDomain(ranDom);
                return node;
            }
            case "str": {
                // Domain format: "sizeLow~sizeHigh(charDomain"
                String exSizeSeg = consumeSegment(exStr, exPos);
                skipParen(exStr, exPos, "exhaustive");
                String ranSizeSeg = consumeSegment(ranStr, ranPos);
                skipParen(ranStr, ranPos, "random");

                List<Integer> exSizeDom = parseIntDomain(exSizeSeg);
                List<Integer> ranSizeDom = parseIntDomain(ranSizeSeg);

                // Char domain is the next segment (stops at next '(' or end)
                String exCharDom = consumeSegment(exStr, exPos);
                String ranCharDom = consumeSegment(ranStr, ranPos);

                if (exCharDom.isEmpty()) {
                    throw new InvalidConfigException(
                        "str exhaustive domain missing char domain");
                }
                if (ranCharDom.isEmpty()) {
                    throw new InvalidConfigException(
                        "str random domain missing char domain");
                }

                // Use exhaustive char domain for the node (should match ran)
                PyStringNode node = new PyStringNode(exCharDom);
                node.setExDomain(exSizeDom);
                node.setRanDomain(ranSizeDom);
                return node;
            }
            default: {
                // Collection types
                if (typeStr.startsWith("list(") && typeStr.endsWith(")")) {
                    String innerType = typeStr.substring(5, typeStr.length() - 1);
                    if (innerType.isEmpty()) {
                        throw new InvalidConfigException("Empty inner type in list()");
                    }
                    return buildIterableNode(
                        "list", innerType, exStr, exPos, ranStr, ranPos);
                }
                if (typeStr.startsWith("set(") && typeStr.endsWith(")")) {
                    String innerType = typeStr.substring(4, typeStr.length() - 1);
                    if (innerType.isEmpty()) {
                        throw new InvalidConfigException("Empty inner type in set()");
                    }
                    return buildIterableNode(
                        "set", innerType, exStr, exPos, ranStr, ranPos);
                }
                if (typeStr.startsWith("tuple(") && typeStr.endsWith(")")) {
                    String innerType = typeStr.substring(6, typeStr.length() - 1);
                    if (innerType.isEmpty()) {
                        throw new InvalidConfigException("Empty inner type in tuple()");
                    }
                    return buildIterableNode(
                        "tuple", innerType, exStr, exPos, ranStr, ranPos);
                }
                if (typeStr.startsWith("dict(") && typeStr.endsWith(")")) {
                    String innerKV = typeStr.substring(5, typeStr.length() - 1);
                    return buildDictNode(innerKV, exStr, exPos, ranStr, ranPos);
                }
                throw new InvalidConfigException("Invalid type: " + typeStr);
            }
        }
    }

    /**
     * Builds a list/set/tuple node with the given inner type.
     * Domain format: "sizeLow~sizeHigh(innerDomain"
     */
    @SuppressWarnings({"unchecked", "rawtypes"})
    private APyNode<?> buildIterableNode(String outerType, String innerType,
                                          String exStr, int[] exPos,
                                          String ranStr, int[] ranPos)
            throws InvalidConfigException {
        // Parse size domain
        String exSizeSeg = consumeSegment(exStr, exPos);
        skipParen(exStr, exPos, "exhaustive");
        String ranSizeSeg = consumeSegment(ranStr, ranPos);
        skipParen(ranStr, ranPos, "random");

        List<Integer> exSizeDom = parseIntDomain(exSizeSeg);
        List<Integer> ranSizeDom = parseIntDomain(ranSizeSeg);

        // Recursively build inner node
        APyNode<?> innerNode = buildNodeHelper(innerType, exStr, exPos, ranStr, ranPos);

        // Build outer node with raw type to avoid unchecked cast issues
        APyNode<?> node;
        switch (outerType) {
            case "list":
                node = new PyListNode(innerNode);
                break;
            case "set":
                node = new PySetNode(innerNode);
                break;
            case "tuple":
                node = new PyTupleNode(innerNode);
                break;
            default:
                throw new InvalidConfigException("Unknown outer type: " + outerType);
        }
        node.setExDomain(exSizeDom);
        node.setRanDomain(ranSizeDom);
        return node;
    }

    /**
     * Builds a dict node.
     * Domain format: "sizeLow~sizeHigh(keyDomain(valueDomain"
     * where keyDomain and valueDomain may themselves contain '(' if nested.
     */
    @SuppressWarnings({"unchecked", "rawtypes"})
    private APyNode<?> buildDictNode(String innerKV,
                                      String exStr, int[] exPos,
                                      String ranStr, int[] ranPos)
            throws InvalidConfigException {
        // Find top-level ':' separating key type from value type
        int colonIdx = findTopLevelColon(innerKV);
        if (colonIdx < 0) {
            throw new InvalidConfigException(
                "Invalid dict type (no ':' found): dict(" + innerKV + ")");
        }
        String keyType = innerKV.substring(0, colonIdx);
        String valType = innerKV.substring(colonIdx + 1);
        if (keyType.isEmpty() || valType.isEmpty()) {
            throw new InvalidConfigException(
                "Invalid dict type (empty key or value type)");
        }

        // Parse size domain
        String exSizeSeg = consumeSegment(exStr, exPos);
        skipParen(exStr, exPos, "exhaustive");
        String ranSizeSeg = consumeSegment(ranStr, ranPos);
        skipParen(ranStr, ranPos, "random");

        List<Integer> exSizeDom = parseIntDomain(exSizeSeg);
        List<Integer> ranSizeDom = parseIntDomain(ranSizeSeg);

        // Parse key node
        APyNode<?> keyNode = buildNodeHelper(keyType, exStr, exPos, ranStr, ranPos);

        // Skip '(' separator between key domain and value domain
        skipParen(exStr, exPos, "exhaustive");
        skipParen(ranStr, ranPos, "random");

        // Parse value node
        APyNode<?> valNode = buildNodeHelper(valType, exStr, exPos, ranStr, ranPos);

        PyDictNode node = new PyDictNode(keyNode, valNode);
        node.setExDomain(exSizeDom);
        node.setRanDomain(ranSizeDom);
        return node;
    }

    // ==================== Domain String Consumers ====================

    /**
     * Consumes characters from str[pos[0]] up to (but not including) the next '('
     * or end of string. Advances pos[0] accordingly.
     */
    private String consumeSegment(String str, int[] pos) {
        int start = pos[0];
        while (pos[0] < str.length() && str.charAt(pos[0]) != '(') {
            pos[0]++;
        }
        return str.substring(start, pos[0]);
    }

    /**
     * Skips a '(' at the current position, advancing pos[0] by 1.
     * Throws if no '(' is present.
     */
    private void skipParen(String str, int[] pos, String domainName)
            throws InvalidConfigException {
        if (pos[0] >= str.length() || str.charAt(pos[0]) != '(') {
            throw new InvalidConfigException(
                "Expected '(' in " + domainName + " domain");
        }
        pos[0]++;
    }

    // ==================== Domain Parsers ====================

    /**
     * Parses an integer domain string: either "lower~upper" or "[v1,v2,...]".
     */
    private List<Integer> parseIntDomain(String domStr) throws InvalidConfigException {
        if (domStr.isEmpty()) {
            throw new InvalidConfigException("Empty domain string");
        }
        if (domStr.startsWith("[")) {
            return parseExplicitIntList(domStr);
        }
        return parseIntRange(domStr);
    }

    /**
     * Parses "lower~upper" into a list [lower, lower+1, ..., upper].
     */
    private List<Integer> parseIntRange(String domStr) throws InvalidConfigException {
        int tildeIdx = domStr.indexOf('~');
        if (tildeIdx < 0) {
            throw new InvalidConfigException(
                "Invalid int range (missing '~'): " + domStr);
        }
        String lowerStr = domStr.substring(0, tildeIdx);
        String upperStr = domStr.substring(tildeIdx + 1);
        try {
            int lower = Integer.parseInt(lowerStr);
            int upper = Integer.parseInt(upperStr);
            if (lower > upper) {
                throw new InvalidConfigException(
                    "Invalid range: lower > upper in " + domStr);
            }
            List<Integer> result = new ArrayList<>();
            for (int v = lower; v <= upper; v++) {
                result.add(v);
            }
            return result;
        } catch (NumberFormatException e) {
            throw new InvalidConfigException(
                "Invalid integer values in range: " + domStr);
        }
    }

    /**
     * Parses "[v1,v2,...]" into a list of integers.
     */
    private List<Integer> parseExplicitIntList(String domStr)
            throws InvalidConfigException {
        if (!domStr.startsWith("[") || !domStr.endsWith("]")) {
            throw new InvalidConfigException(
                "Invalid explicit list (missing brackets): " + domStr);
        }
        String inner = domStr.substring(1, domStr.length() - 1);
        if (inner.isEmpty()) {
            return new ArrayList<>();
        }
        List<Integer> result = new ArrayList<>();
        for (String s : inner.split(",")) {
            try {
                result.add(Integer.parseInt(s.trim()));
            } catch (NumberFormatException e) {
                throw new InvalidConfigException(
                    "Invalid integer in explicit list: " + s);
            }
        }
        return result;
    }

    /**
     * Parses a float domain string: either "lower~upper" or "[v1,v2,...]".
     */
    private List<Double> parseFloatDomain(String domStr) throws InvalidConfigException {
        if (domStr.isEmpty()) {
            throw new InvalidConfigException("Empty float domain string");
        }
        if (domStr.startsWith("[")) {
            return parseExplicitFloatList(domStr);
        }
        return parseFloatRange(domStr);
    }

    /**
     * Parses "lower~upper" (floats, step=1.0) into a list of doubles.
     */
    private List<Double> parseFloatRange(String domStr) throws InvalidConfigException {
        int tildeIdx = domStr.indexOf('~');
        if (tildeIdx < 0) {
            throw new InvalidConfigException(
                "Invalid float range (missing '~'): " + domStr);
        }
        String lowerStr = domStr.substring(0, tildeIdx);
        String upperStr = domStr.substring(tildeIdx + 1);
        try {
            double lower = Double.parseDouble(lowerStr);
            double upper = Double.parseDouble(upperStr);
            if (lower > upper + 1e-9) {
                throw new InvalidConfigException(
                    "Invalid float range: lower > upper in " + domStr);
            }
            List<Double> result = new ArrayList<>();
            for (double v = lower; v <= upper + 1e-9; v += 1.0) {
                result.add(v);
            }
            return result;
        } catch (NumberFormatException e) {
            throw new InvalidConfigException(
                "Invalid float values in range: " + domStr);
        }
    }

    /**
     * Parses "[v1,v2,...]" into a list of doubles.
     */
    private List<Double> parseExplicitFloatList(String domStr)
            throws InvalidConfigException {
        if (!domStr.startsWith("[") || !domStr.endsWith("]")) {
            throw new InvalidConfigException(
                "Invalid explicit float list: " + domStr);
        }
        String inner = domStr.substring(1, domStr.length() - 1);
        if (inner.isEmpty()) {
            return new ArrayList<>();
        }
        List<Double> result = new ArrayList<>();
        for (String s : inner.split(",")) {
            try {
                result.add(Double.parseDouble(s.trim()));
            } catch (NumberFormatException e) {
                throw new InvalidConfigException(
                    "Invalid float in explicit list: " + s);
            }
        }
        return result;
    }

    // ==================== Type String Helpers ====================

    /**
     * Finds the index of ':' at depth 0 in s (for parsing dict key:value types).
     * Returns -1 if not found.
     */
    private int findTopLevelColon(String s) {
        int depth = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == '(') {
                depth++;
            } else if (c == ')') {
                depth--;
            } else if (c == ':' && depth == 0) {
                return i;
            }
        }
        return -1;
    }
}

package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import java.util.Set;

/**
 * Entry point that ties together parsing, test generation, running, and set selection.
 */
public class Main {

    /**
     * Generates a concise set of test cases that catches all known buggy implementations.
     *
     * @param args {configPath, solutionPath, implDirPath}
     * @return a minimal set of TestCases that covers all buggy implementations
     * @throws IOException            if any file cannot be read
     * @throws InvalidConfigException if the config file is malformed
     * @throws InterruptedException   if a subprocess is interrupted
     */
    public static Set<TestCase> generateTests(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {
        String configPath = args[0];
        String solutionPath = args[1];
        String implDirPath = args[2];

        // Step 1: Parse the config file
        String configContents = Files.readString(Paths.get(configPath));
        ConfigFileParser parser = new ConfigFileParser();
        ConfigFile config = parser.parse(configContents);

        // Step 2: Generate the base test set
        BaseSetGenerator generator =
            new BaseSetGenerator(config.getNodes(), config.getNumRand());
        List<TestCase> baseTests = generator.genBaseSet();

        // Step 3: Run the tests against the solution and all implementations
        Tester tester = new Tester(
            config.getFuncName(), solutionPath, implDirPath, baseTests);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // Step 4: Select the concise (approximately minimal) set of test cases
        return ConciseSetGenerator.setCover(results);
    }

    /**
     * Command-line entry point.
     *
     * @param args {configPath, solutionPath, implDirPath}
     */
    public static void main(String[] args) throws Exception {
        if (args.length < 3) {
            System.err.println("Usage: Main <configPath> <solutionPath> <implDirPath>");
            System.exit(1);
        }
        Set<TestCase> tests = generateTests(args);
        System.out.println("Concise test set size: " + tests.size());
        for (TestCase tc : tests) {
            System.out.println(tc);
        }
    }
}
